extension Endpoint {
    static func tmdbAuthenticationValidateKey() -> Endpoint {
        let path = "/authentication"
        let queryItems: [URLQueryItem] = []
        return Endpoint(
            path: path,
            method: .get,
            queryItems: queryItems,
            body: nil
        )
    }

    static func tmdbAccountDetails(accountId: Int, sessionId: String?) -> Endpoint {
        var path = "/account/{account_id}"
        path = path.replacingOccurrences(of: "{account_id}", with: String(accountId))
        let queryItems = tmdbQueryItems([
            ("session_id", sessionId),
        ])
        return Endpoint(
            path: path,
            method: .get,
            queryItems: queryItems,
            body: nil
        )
    }

    static func tmdbAccountAddFavorite(accountId: Int, sessionId: String?, body: TMDBAccountAddFavoriteRequestDTO) throws -> Endpoint {
        var path = "/account/{account_id}/favorite"
        path = path.replacingOccurrences(of: "{account_id}", with: String(accountId))
        let queryItems = tmdbQueryItems([
            ("session_id", sessionId),
        ])
        return Endpoint(
            path: path,
            method: .post,
            queryItems: queryItems,
            body: try JSONEncoder.tmdbGenerated.encode(body)
        )
    }

